solution:
function createInMemoryModel() {
  let docs = [];
  let nextId = 1;

  return {
    async create(data) {
      const doc = { _id: String(nextId++), ...data };
      docs.push(doc);
      return doc;
    },
    async find() {
      return docs.slice();
    },
    async findById(id) {
      return docs.find((d) => d._id === id) || null;
    },
    async findByIdAndUpdate(id, changes) {
      const doc = docs.find((d) => d._id === id);
      if (!doc) return null;
      Object.assign(doc, changes);
      return doc;
    },
    async deleteOne(filter) {
      const index = docs.findIndex((d) => d._id === filter._id);
      if (index === -1) return { deletedCount: 0 };
      docs.splice(index, 1);
      return { deletedCount: 1 };
    },
  };
}

module.exports = { createInMemoryModel };
